function isScheduleInRange(schedule, quoteDate){
  if(!schedule?.isActive||!quoteDate)return !!schedule?.isActive;
  return schedule.effectiveFrom<=quoteDate && (!schedule.effectiveTo || schedule.effectiveTo>=quoteDate);
}
function resolveRateSchedule(quote, schedules){
  const all=(schedules||[]).filter(Boolean);
  const byId = quote?.rateScheduleId ? all.find(s=>s.id===quote.rateScheduleId) : null;
  if(byId) return byId;
  const inRange = all.filter(s=>isScheduleInRange(s, quote?.quoteDate)).sort((a,b)=>(b.effectiveFrom||'').localeCompare(a.effectiveFrom||''));
  return inRange[0] || DEFAULT_RATE_SCHEDULES[0];
}
function getScheduleItem(schedule, code, fallback=0){
  const item=schedule?.items?.find(i=>i.code===code);
  return item?.amount ?? fallback;
}
function getRoleRate(schedule, roleCode){
  const item=schedule?.items?.find(i=>i.code===roleCode && i.category==='labour');
  return item?.amounts || ROLES[roleCode];
}
