// Dynamic holiday cache — updated from storage on load
let HOLIDAY_PH_SET = new Set(DEFAULT_HOLIDAYS.filter(h=>h.type==="Public Holiday").map(h=>h.date));
function syncHolidayCache(holidays) {
  HOLIDAY_PH_SET = new Set(holidays.filter(h=>h.type==="Public Holiday").map(h=>h.date));
}

// ─── CALCULATION ENGINE ───────────────────────────────────────────
const toYMD=d=>d.toISOString().split("T")[0];
const parseD=s=>{if(!s)return null;const[y,m,d]=s.split("-").map(Number);return isNaN(y)?null:new Date(y,m-1,d);};

function countDays(start,end,excludedDows=[]){
  const s=parseD(start),e=parseD(end);
  if(!s||!e||s>e)return{wkd:0,sat:0,sun:0,ph:0,total:0};
  const ex=new Set(excludedDows);let wkd=0,sat=0,sun=0,ph=0;
  const cur=new Date(s);
  while(cur<=e){
    const dow=cur.getDay();
    if(!ex.has(dow)){
      const str=toYMD(cur);
      if(HOLIDAY_PH_SET.has(str))ph++;
      else if(dow===6)sat++;
      else if(dow===0)sun++;
      else wkd++;
    }
    cur.setDate(cur.getDate()+1);
  }
  return{wkd,sat,sun,ph,total:wkd+sat+sun+ph};
}

function shiftHrs(s){
  const oh=parseFloat(s.overrideHrs);
  if(!isNaN(oh)&&oh>0)return oh;
  const ss=parseFloat(s.shiftStart),se=parseFloat(s.shiftEnd);
  if(isNaN(ss)||isNaN(se))return null;
  return se>=ss?se-ss:24+se-ss;
}

function calcShift(s,schedule){
  if(s.type==="rdo")return null;
  if(!s.role||!s.staff||!s.startDate||!s.endDate)return null;
  const hrs=shiftHrs(s);if(!hrs||hrs<=0)return null;
  const n=parseFloat(s.staff);if(isNaN(n)||n<=0)return null;
  const r=getRoleRate(schedule,s.role);if(!r)return null;
  const d=countDays(s.startDate,s.endDate,s.excludedDows||[]);
  const ss=parseFloat(s.shiftStart);
  const isNight=!s.overrideHrs&&!isNaN(ss)&&ss>=18;
  const ST=Math.min(hrs,7.6),OT=Math.max(0,hrs-7.6);
  const dr=isNight?r.night:r.day;
  const wkdCost=n*d.wkd*(ST*dr+Math.min(OT,3)*r.ot1+Math.max(0,OT-3)*r.ot2);
  const satCost=n*d.sat*hrs*r.sat,sunCost=n*d.sun*hrs*r.sun,phCost=n*d.ph*hrs*r.ph;
  return{wkd:d.wkd,sat:d.sat,sun:d.sun,ph:d.ph,totalDays:d.total,hrs,isNight,wkdCost,satCost,sunCost,phCost,cost:wkdCost+satCost+sunCost+phCost,n,totalHrs:n*d.total*hrs,
         ST,OT,dr,rate:r};
}

function jobSpan(shifts){
  const f=shifts.filter(s=>s.startDate&&s.endDate);
  if(!f.length)return 0;
  const starts=f.map(s=>parseD(s.startDate)?.getTime()).filter(Boolean);
  const ends=f.map(s=>parseD(s.endDate)?.getTime()).filter(Boolean);
  return Math.round((Math.max(...ends)-Math.min(...starts))/86400000)+1;
}

function calcOTMeal(shifts,schedule){
  return shifts.filter(s=>s.type!=="rdo").reduce((t,s)=>{
    const hrs=shiftHrs(s);
    if(!hrs||hrs<=7.6||!s.role||!s.staff||!s.startDate||!s.endDate)return t;
    return t+(parseFloat(s.staff)||0)*countDays(s.startDate,s.endDate,s.excludedDows||[]).wkd*getScheduleItem(schedule,"OT_MEAL_QR",21.17);
  },0);
}

function calcSummary(q,schedule){
  const shiftCalcs=q.shifts.map(s=>calcShift(s,schedule));
  const labour=shiftCalcs.reduce((t,r)=>t+(r?.cost||0),0);
  const otMeal=calcOTMeal(q.shifts,schedule);
  const span=q.vehicleDaysOverride?(parseFloat(q.vehicleDaysOverride)||0):jobSpan(q.shifts);
  const numVeh=parseFloat(q.numVehicles)||0;
  const vehicleHire=numVeh>0&&span>0?numVeh*span*getScheduleItem(schedule,"VEHICLE_INTERNAL_DAY",186.72):0;
  const km=parseFloat(q.kmPerDay)||0;
  const kmCharge=km>50?Math.max(0,km-50)*getScheduleItem(schedule,"KM_AFTER_50",0.28)*numVeh*span:0;
  const acAmt=q.includeAccom?(parseFloat(q.accomAmount)||0):0;
  const accommodation=acAmt>0?(q.accomType==="COST + 10%"?acAmt*(1+getScheduleItem(schedule,"FLIGHT_MARKUP",0.10)):acAmt*getScheduleItem(schedule,"ACCOM_FIXED",350.80)):0;
  const regSD=q.shifts.filter(s=>s.type!=="rdo").reduce((t,s)=>{
    if(!s.role||!s.staff||!s.startDate||!s.endDate)return t;
    return t+(parseFloat(s.staff)||0)*countDays(s.startDate,s.endDate,s.excludedDows||[]).total;
  },0);
  const rdoSD=q.shifts.filter(s=>s.type==="rdo").reduce((t,s)=>{
    if(!s.startDate||!s.endDate||!s.staff)return t;
    return t+(parseFloat(s.staff)||0)*countDays(s.startDate,s.endDate,[]).total;
  },0);
  const staffDays=regSD+rdoSD;
  const breakfast=q.inclBreakfast?staffDays*getScheduleItem(schedule,"BREAKFAST",26.76):0;
  const lunch=q.inclLunch?staffDays*getScheduleItem(schedule,"LUNCH",30.05):0;
  const dinner=q.inclDinner?staffDays*getScheduleItem(schedule,"DINNER",51.60):0;
  const flightAmt=parseFloat(q.flightCost)||0;
  const flights=flightAmt>0?flightAmt*(1+getScheduleItem(schedule,"FLIGHT_MARKUP",0.10)):0;
  const planning=(parseFloat(q.planMF)||0)*getScheduleItem(schedule,"PLAN_MF",94.19)+(parseFloat(q.planSat)||0)*getScheduleItem(schedule,"PLAN_SAT",139.25)+(parseFloat(q.planSun)||0)*getScheduleItem(schedule,"PLAN_SUN",176.26)+(parseFloat(q.planPH)||0)*getScheduleItem(schedule,"PLAN_PH",213.26);
  const subtotal=labour+otMeal+vehicleHire+kmCharge+accommodation+breakfast+lunch+dinner+flights+planning;
  const gst=subtotal*0.1,total=subtotal+gst;
  const cancellation=q.shifts.filter(s=>s.type!=="rdo").reduce((t,s)=>{
    if(!s.role||!s.staff)return t;
    const r=getRoleRate(schedule,s.role);if(!r)return t;
    return t+7.6*r.day*(parseFloat(s.staff)||0);
  },0);
  return{labour,otMeal,vehicleHire,kmCharge,accommodation,breakfast,lunch,dinner,flights,planning,subtotal,gst,total,cancellation,span,numVeh,shiftCalcs,staffDays,schedule};
}

// Show day warning detection
function detectShowDayWarnings(officers,shifts,allHolidays,staffList){
  const showDays=allHolidays.filter(h=>h.type==="Show Day");
  if(!showDays.length)return[];
  const enriched=officers.filter(o=>o.name).map(o=>{
    if(o.location)return o;
    const m=staffList.find(s=>s.name.toLowerCase().trim()===o.name.toLowerCase().trim());
    return m?{...o,location:m.location}:o;
  }).filter(o=>o.location);
  if(!enriched.length)return[];
  const warnings=[];
  shifts.forEach((shift,si)=>{
    if(!shift.startDate||!shift.endDate)return;
    const start=parseD(shift.startDate),end=parseD(shift.endDate);
    if(!start||!end)return;
    enriched.forEach(officer=>{
      showDays.forEach(sd=>{
        const sdDate=parseD(sd.date);
        if(!sdDate||sdDate<start||sdDate>end)return;
        const loc=(officer.location||"").toLowerCase();
        const reg=(sd.region||"").toLowerCase();
        if(!reg)return;
        const words=reg.split(/[\s,\/\-]+/).filter(w=>w.length>2);
        if(words.some(w=>loc.includes(w))){
          warnings.push({shiftIndex:si,officer:officer.name,location:officer.location,holiday:sd.name,date:sd.date,state:sd.state});
        }
      });
    });
  });
  return warnings;
}


