const fmtD=s=>{const d=parseD(s);return d?d.toLocaleDateString("en-AU",{day:"numeric",month:"short",year:"2-digit"}):""};
const fmtDLong=s=>{const d=parseD(s);return d?d.toLocaleDateString("en-AU",{day:"numeric",month:"long",year:"numeric"}):""};
const fmtT=t=>{const n=parseFloat(t);if(isNaN(n))return"";const h=Math.floor(n),m=Math.round((n%1)*60);return`${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}`};
const fmtPhone=s=>{if(!s)return"";const d=s.replace(/\D/g,"");if(d.length===10&&d.startsWith("04"))return`${d.slice(0,4)} ${d.slice(4,7)} ${d.slice(7)}`;if(d.length===10)return`${d.slice(0,2)} ${d.slice(2,6)} ${d.slice(6)}`;return s;};
const fmtDateTime=s=>{try{return new Date(s).toLocaleString("en-AU",{day:"numeric",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"});}catch{return s;}};
