const PFX_Q="tps4:q:",IDX_Q="tps4:idx",KEY_C="tps4:contacts",KEY_S="tps4:staff",
      KEY_H="tps4:holidays",KEY_T="tps4:templates",KEY_R="tps4:rateSchedules",KEY_USER="tps4:user";

async function saveQuote(q,total){
  try{
    const upd={...q,updatedAt:new Date().toISOString()};
    await window.storage.set(`${PFX_Q}${q.id}`,JSON.stringify(upd),true);
    let idx=[];try{const r=await window.storage.get(IDX_Q,true);if(r)idx=JSON.parse(r.value);}catch{}
    idx=idx.filter(m=>m.id!==q.id);
    idx.unshift({id:q.id,quoteNo:q.quoteNo||"Draft",preparedFor:q.preparedFor,company:q.company,date:q.quoteDate,total,version:q.version||1});
    await window.storage.set(IDX_Q,JSON.stringify(idx),true);
    return upd;
  }catch{return null;}
}
async function loadIndex(){try{const r=await window.storage.get(IDX_Q,true);return r?JSON.parse(r.value):[];}catch{return[];}}
async function loadQuote(id){try{const r=await window.storage.get(`${PFX_Q}${id}`,true);return r?JSON.parse(r.value):null;}catch{return null;}}
async function deleteQuote(id){
  try{
    await window.storage.delete(`${PFX_Q}${id}`,true);
    let idx=[];try{const r=await window.storage.get(IDX_Q,true);if(r)idx=JSON.parse(r.value);}catch{}
    await window.storage.set(IDX_Q,JSON.stringify(idx.filter(m=>m.id!==id)),true);
    return true;
  }catch{return false;}
}
