async function loadStaff(){try{const r=await window.storage.get(KEY_S,true);return r?JSON.parse(r.value):INITIAL_STAFF;}catch{return INITIAL_STAFF;}}
async function saveStaff(ss){try{await window.storage.set(KEY_S,JSON.stringify(ss),true);return true;}catch{return false;}}
async function loadHolidays(){try{const r=await window.storage.get(KEY_H,true);return r?JSON.parse(r.value):DEFAULT_HOLIDAYS;}catch{return DEFAULT_HOLIDAYS;}}
async function saveHolidays(hs){try{await window.storage.set(KEY_H,JSON.stringify(hs),true);return true;}catch{return false;}}
async function loadTemplates(){try{const r=await window.storage.get(KEY_T,true);return r?JSON.parse(r.value):[];}catch{return[];}}
async function saveTemplates(ts){try{await window.storage.set(KEY_T,JSON.stringify(ts),true);return true;}catch{return false;}}
async function loadRateSchedules(){try{const r=await window.storage.get(KEY_R,true);return r?JSON.parse(r.value):DEFAULT_RATE_SCHEDULES;}catch{return DEFAULT_RATE_SCHEDULES;}}
async function saveRateSchedules(list){try{await window.storage.set(KEY_R,JSON.stringify(list),true);return true;}catch{return false;}}
async function loadUser(){try{const r=await window.storage.get(KEY_USER,false);return r?r.value:"TPS Admin";}catch{return"TPS Admin";}}
async function saveUser(name){try{await window.storage.set(KEY_USER,name,false);return true;}catch{return false;}}

