    if(!editing.name.trim()){showToast("Name is required","err");return;}
    setSaving(true);
    const list=editing.id&&contacts.find(c=>c.id===editing.id)?contacts.map(c=>c.id===editing.id?editing:c):[...contacts,{...editing,id:Date.now().toString()}];
